// Build standard tick envelope; consumed by all per-entity inject-config nodes downstream
const t = msg.payload || {};
msg.payload = {
    base_seed:    Number(env.get('BASE_SEED') || 12345),
    timestamp_ms: t.timestamp_ms || Date.now(),
    timestamp:    t.timestamp    || new Date().toISOString(),
    site_id:      env.get('SITE_ID') || "site-berlin-001",
    mode:         env.get('MODE') || 'normal'
};
// One-shot: bump engine.registered_entities on first tick
const engine = global.get('engine');
if (engine && engine.registered_entities !== 21) {
    engine.registered_entities = 21;
    global.set('engine', engine);
}
return msg;

